export default function TabsLayout() {
  const insets = useSafeAreaInsets();
  // Add 16px on top of whatever the safe area reports so the system nav bar
  // never overlaps the tab bar — handles both gesture nav and 3-button nav.
  const bottomPad = Math.max(insets.bottom, 16) + 16;
  const tabBarHeight = 56 + bottomPad;

  return (
    <Tabs
      screenOptions={{
        headerShown: false,
        tabBarStyle: {
          backgroundColor: "#1C1F26",
          borderTopColor: colors.border,
          borderTopWidth: 1,
          height: tabBarHeight,
          paddingBottom: bottomPad,
          paddingTop: 6,
        },
        tabBarActiveTintColor: colors.tabActive,
        tabBarInactiveTintColor: "#BCBCBE",
        tabBarLabelStyle: {
          fontSize: isSmallScreen ? 9 : 10,
          fontWeight: "500",
          marginTop: 2,
        },
      }}
    >
      <Tabs.Screen
        name="index"
        options={{
          title: "Home",
          tabBarIcon: ({ color }) => <HomeIcon color={color} />,
        }}
      />
      <Tabs.Screen
        name="menu"
        options={{
          title: isSmallScreen ? "A-Z" : "A-Z Menu",
          tabBarIcon: ({ color }) => <MenuIcon color={color} />,
        }}
      />
      <Tabs.Screen
        name="games"
        options={{
          title: "Games",
          tabBarIcon: ({ color }) => <GamesIcon color={color} />,
        }}
      />
      <Tabs.Screen
        name="ticket"
        options={{
          title: "Ticket",
          tabBarIcon: ({ color }) => <TicketIcon color={color} />,
        }}
      />
      <Tabs.Screen
        name="profile"
        options={{
          title: "Profile",
          tabBarIcon: ({ color }) => <ProfileIcon color={color} />,
        }}
      />
    </Tabs>
  );
}
